/* Search index — trasforma PRODUCTS nel formato atteso da search-data.js */
window.ATH_DATA_JSON = {
  products: (window.PRODUCTS || []).map(function(p) {
    var line = (window.LINES || []).find(function(l) { return l.id === p.line; });
    var brand = line ? (line.brand || 'erboristica') : (p.brand || 'erboristica');
    var actives = [];
    if (p.it && Array.isArray(p.it.actives)) {
      actives = p.it.actives.map(function(a) { return a.split(' — ')[0].split(' — ')[0].trim(); });
    }
    return {
      id: p.id,
      name_it: p.it ? (p.it.name || '') : '',
      subtitle_it: p.it ? (p.it.sub || '') : '',
      line: p.line,
      line_name: line ? (line.shortName || line.name || '') : '',
      brand: brand,
      actives_main: actives
    };
  })
};
